export function createClient(config: ClientConfig): RateGuardClient {
  return new RateGuardClient(config);
}

export function middleware(config: ClientConfig = { baseUrl: "http://localhost:8008" }) {
  const client = createClient(config);
  return (req: any, _res: any, next: any) => {
    req.rateguard = client;
    if (typeof next === "function") return next();
  };
}
